import{_ as o,o as t,c as e,a3 as r}from"./chunks/framework.CVjg771q.js";const g=JSON.parse('{"title":"道德经 · 帛书甲本","description":"","frontmatter":{},"headers":[],"relativePath":"daoism/dao-de-jing-boshu/index.md","filePath":"daoism/dao-de-jing-boshu/index.md","lastUpdated":1780591578000}'),i={name:"daoism/dao-de-jing-boshu/index.md"};function l(n,a,s,d,h,u){return t(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="道德经-·-帛书甲本" tabindex="-1">道德经 · 帛书甲本 <a class="header-anchor" href="#道德经-·-帛书甲本" aria-label="Permalink to &quot;道德经 · 帛书甲本&quot;">​</a></h1><blockquote><p>1973年长沙马王堆三号汉墓出土。甲本抄写于汉高祖时期（约公元前206–前195年），是目前所见最早的《老子》完整写本之一。</p></blockquote><h2 id="版本特点" tabindex="-1">版本特点 <a class="header-anchor" href="#版本特点" aria-label="Permalink to &quot;版本特点&quot;">​</a></h2><ul><li><strong>篇序不同</strong>：帛书本 <strong>德经在前、道经在后</strong>，与通行本相反</li><li><strong>文字更古</strong>：作「恒」（非「常」）、「邦」（非「国」）等，保留战国文字特征，反映避讳制度变迁</li><li><strong>甲本最优</strong>：脱漏较少，内容完整，优于乙本及后来的郭店简本</li><li><strong>分章说明</strong>：八十一章为后人划分，为检索方便仍沿用，与通行本基本保持一致</li><li><strong>校对原则</strong>：以甲本为准，甲本缺失取乙本，乙本缺失取通行本；不通则以通者为准</li></ul><h2 id="篇章索引" tabindex="-1">篇章索引 <a class="header-anchor" href="#篇章索引" aria-label="Permalink to &quot;篇章索引&quot;">​</a></h2><h3 id="德经-帛书第1–44章-·-通行本第38–81章" tabindex="-1">德经（帛书第1–44章 · 通行本第38–81章） <a class="header-anchor" href="#德经-帛书第1–44章-·-通行本第38–81章" aria-label="Permalink to &quot;德经（帛书第1–44章 · 通行本第38–81章）&quot;">​</a></h3><p>帛书以德经开篇，论述修身、治国、处世之道。</p><h3 id="道经-帛书第45–81章-·-通行本第1–37章" tabindex="-1">道经（帛书第45–81章 · 通行本第1–37章） <a class="header-anchor" href="#道经-帛书第45–81章-·-通行本第1–37章" aria-label="Permalink to &quot;道经（帛书第45–81章 · 通行本第1–37章）&quot;">​</a></h3><p>论述宇宙本源、道法自然、哲理本体。</p><h2 id="阅读建议" tabindex="-1">阅读建议 <a class="header-anchor" href="#阅读建议" aria-label="Permalink to &quot;阅读建议&quot;">​</a></h2><ol><li><strong>初读只读原文</strong>：对原文及注释稍作了解即可，不必强求深解</li><li><strong>对照通行本</strong>：每章标注对应通行本章号，可逐章对比异同</li><li><strong>注意异文</strong>：「恒道」与「常道」、「邦」与「国」之变，涉及汉代避讳制度</li><li><strong>关注括号注</strong>：文中如&quot;泊（薄）&quot;表示帛书作&quot;泊&quot;，据通行本校读为&quot;薄&quot;</li></ol><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li><li>高明《帛书老子校注》</li></ul><h2 id="版本比较" tabindex="-1">版本比较 <a class="header-anchor" href="#版本比较" aria-label="Permalink to &quot;版本比较&quot;">​</a></h2><ul><li><a href="/Dao/kaoju/dao-de-jing/">进入《道德经》通行本 vs 帛书版考据</a></li></ul>',15)])])}const q=o(i,[["render",l]]);export{g as __pageData,q as default};
